+    harness
+        .log()
+        .info_ctx("json_parity", "lifecycle ordering ok", |ctx| {
+            ctx.push(("events".to_string(), json_lines.len().to_string()));
+            ctx.push((
+                "order".to_string(),
+                expected_order.join(","),
+            ));
+        });
+}
